<template>
  <div class="sql-generator-tool">
    <el-card>
      <div slot="header">
        <span>SQL 生成器</span>
        <el-button-group class="header-actions">
          <el-button size="small" @click="clearAll">清空</el-button>
          <el-button size="small" @click="loadExample" type="primary">加载示例</el-button>
        </el-button-group>
      </div>

      <el-row :gutter="20">
        <el-col :span="12">
          <el-card shadow="hover">
            <div slot="header">
              <span>JSON 数据</span>
              <el-button size="small" @click="importJson" type="info">导入</el-button>
            </div>
            <el-input
              type="textarea"
              :rows="15"
              v-model="jsonData"
              placeholder="输入 JSON 格式的数据..."
              @change="generateSql"
            />
          </el-card>

          <el-card shadow="hover" style="margin-top: 20px">
            <div slot="header">
              <span>生成配置</span>
            </div>
            <el-form :model="config" label-width="100px">
              <el-form-item label="表名">
                <el-input v-model="config.tableName" @change="generateSql" placeholder="输入表名" />
              </el-form-item>
              <el-form-item label="SQL 类型">
                <el-select v-model="config.sqlType" @change="generateSql" style="width: 100%">
                  <el-option label="INSERT" value="insert" />
                  <el-option label="UPDATE" value="update" />
                  <el-option label="DELETE" value="delete" />
                  <el-option label="SELECT" value="select" />
                </el-select>
              </el-form-item>
              <el-form-item label="批量插入">
                <el-switch v-model="config.batchInsert" @change="generateSql" />
              </el-form-item>
              <el-form-item label="包含 ID">
                <el-switch v-model="config.includeId" @change="generateSql" />
              </el-form-item>
              <el-form-item label="数据库类型">
                <el-select v-model="config.databaseType" @change="generateSql" style="width: 100%">
                  <el-option label="MySQL" value="mysql" />
                  <el-option label="PostgreSQL" value="postgresql" />
                  <el-option label="SQL Server" value="sqlserver" />
                  <el-option label="Oracle" value="oracle" />
                </el-select>
              </el-form-item>
            </el-form>
          </el-card>
        </el-col>

        <el-col :span="12">
          <el-card shadow="hover">
            <div slot="header">
              <span>生成结果</span>
              <el-button size="small" @click="copySql" type="success">复制</el-button>
            </div>
            <el-input
              type="textarea"
              :rows="15"
              :value="generatedSql"
              readonly
              class="code-area"
            />
          </el-card>

          <el-card shadow="hover" style="margin-top: 20px">
            <div slot="header">
              <span>数据预览</span>
            </div>
            <el-table
              :data="parsedData.slice(0, 5)"
              border
              style="width: 100%"
              size="small"
            >
              <el-table-column
                v-for="field in fields"
                :key="field"
                :prop="field"
                :label="field"
                min-width="100"
              />
            </el-table>
            <div v-if="parsedData.length > 5" style="text-align: center; margin-top: 10px; color: #909399">
              仅显示前 5 条数据
            </div>
          </el-card>
        </el-col>
      </el-row>
    </el-card>
  </div>
</template>

<script>
export default {
  name: 'SqlGeneratorTool',
  data() {
    return {
      jsonData: '',
      parsedData: [],
      fields: [],
      config: {
        tableName: 'users',
        sqlType: 'insert',
        batchInsert: true,
        includeId: false,
        databaseType: 'mysql'
      },
      generatedSql: ''
    }
  },
  methods: {
    clearAll() {
      this.jsonData = ''
      this.parsedData = []
      this.fields = []
      this.config = {
        tableName: 'users',
        sqlType: 'insert',
        batchInsert: true,
        includeId: false,
        databaseType: 'mysql'
      }
      this.generatedSql = ''
    },
    loadExample() {
      this.jsonData = JSON.stringify([
        {
          "id": 1,
          "name": "John Doe",
          "email": "john@example.com",
          "age": 30,
          "active": true,
          "created_at": "2023-01-01T00:00:00Z"
        },
        {
          "id": 2,
          "name": "Jane Smith",
          "email": "jane@example.com",
          "age": 25,
          "active": true,
          "created_at": "2023-01-02T00:00:00Z"
        },
        {
          "id": 3,
          "name": "Bob Johnson",
          "email": "bob@example.com",
          "age": 35,
          "active": false,
          "created_at": "2023-01-03T00:00:00Z"
        }
      ], null, 2)
      this.generateSql()
    },
    generateSql() {
      try {
        const data = JSON.parse(this.jsonData)
        if (Array.isArray(data)) {
          this.parsedData = data
          if (data.length > 0) {
            this.fields = Object.keys(data[0])
            this.fields = this.config.includeId ? this.fields : this.fields.filter(field => field.toLowerCase() !== 'id')
            
            if (this.config.sqlType === 'insert') {
              this.generateInsertSql(data)
            } else if (this.config.sqlType === 'update') {
              this.generateUpdateSql(data)
            } else if (this.config.sqlType === 'delete') {
              this.generateDeleteSql(data)
            } else if (this.config.sqlType === 'select') {
              this.generateSelectSql(data)
            }
          }
        } else {
          this.$message.error('JSON 数据必须是数组格式')
        }
      } catch (error) {
        this.$message.error('JSON 格式错误')
      }
    },
    generateInsertSql(data) {
      if (data.length === 0 || this.fields.length === 0) {
        this.generatedSql = ''
        return
      }
      
      const tableName = this.config.tableName
      const fields = this.fields
      
      if (this.config.batchInsert) {
        let sql = `INSERT INTO ${tableName} (${fields.join(', ')}) VALUES\n`
        const values = data.map(item => {
          const rowValues = fields.map(field => {
            return this.formatValue(item[field])
          })
          return `  (${rowValues.join(', ')})`
        })
        sql += values.join(',\n')
        sql += ';'
        this.generatedSql = sql
      } else {
        const sqls = data.map(item => {
          const values = fields.map(field => {
            return this.formatValue(item[field])
          })
          return `INSERT INTO ${tableName} (${fields.join(', ')}) VALUES (${values.join(', ')});`
        })
        this.generatedSql = sqls.join('\n')
      }
    },
    generateUpdateSql(data) {
      if (data.length === 0 || this.fields.length === 0) {
        this.generatedSql = ''
        return
      }
      
      const tableName = this.config.tableName
      const fields = this.fields
      const idField = this.fields.find(field => field.toLowerCase() === 'id') || fields[0]
      
      const sqls = data.map(item => {
        const setClauses = fields
          .filter(field => field !== idField)
          .map(field => {
            return `${field} = ${this.formatValue(item[field])}`
          })
        return `UPDATE ${tableName} SET ${setClauses.join(', ')} WHERE ${idField} = ${this.formatValue(item[idField])};`
      })
      this.generatedSql = sqls.join('\n')
    },
    generateDeleteSql(data) {
      if (data.length === 0) {
        this.generatedSql = ''
        return
      }
      
      const tableName = this.config.tableName
      const idField = this.fields.find(field => field.toLowerCase() === 'id') || this.fields[0]
      
      if (data.length === 1) {
        const item = data[0]
        this.generatedSql = `DELETE FROM ${tableName} WHERE ${idField} = ${this.formatValue(item[idField])};`
      } else {
        const ids = data.map(item => this.formatValue(item[idField]))
        this.generatedSql = `DELETE FROM ${tableName} WHERE ${idField} IN (${ids.join(', ')});`
      }
    },
    generateSelectSql(data) {
      if (this.fields.length === 0) {
        this.generatedSql = ''
        return
      }
      
      const tableName = this.config.tableName
      const fields = this.fields
      
      this.generatedSql = `SELECT ${fields.join(', ')} FROM ${tableName};`
    },
    formatValue(value) {
      if (value === null || value === undefined) {
        return 'NULL'
      }
      
      switch (typeof value) {
        case 'string':
          return `'${value.replace(/'/g, "''")}'`
        case 'number':
          return value
        case 'boolean':
          return this.config.databaseType === 'mysql' || this.config.databaseType === 'postgresql' ? (value ? '1' : '0') : (value ? 'TRUE' : 'FALSE')
        case 'object':
          if (value instanceof Date) {
            return `'${value.toISOString()}'`
          } else {
            return `'${JSON.stringify(value).replace(/'/g, "''")}'`
          }
        default:
          return `'${String(value).replace(/'/g, "''")}'`
      }
    },
    copySql() {
      this.$copyText(this.generatedSql).then(() => {
        this.$message.success('SQL 语句已复制到剪贴板')
      })
    },
    importJson() {
      const input = document.createElement('input')
      input.type = 'file'
      input.accept = '.json'
      input.onchange = (e) => {
        const file = e.target.files[0]
        if (file) {
          const reader = new FileReader()
          reader.onload = (e) => {
            this.jsonData = e.target.result
            this.generateSql()
          }
          reader.readAsText(file)
        }
      }
      input.click()
    }
  }
}
</script>

<style lang="scss" scoped>
.sql-generator-tool {
  .header-actions {
    float: right;
  }
  
  .code-area {
    font-family: 'Courier New', monospace;
    font-size: 14px;
    line-height: 1.5;
  }
}
</style>